// ─────────────────────────────────────────────────────────────────────────────
// 2. CONSTANTS
// ─────────────────────────────────────────────────────────────────────────────

let signalHandlersInstalled = false;
const DEFAULT_WRITER_LOCK_MAX_WAIT_MS = 1_000;
const DEFAULT_WRITER_LOCK_RETRY_INTERVAL_MS = 25;
