        AND n.kind = 'DIMENSION'
    `).get(...edgeNamespace.params, fileId) as { c: number }).c;

    if (dimCoverage >= 2) saturated++;
  }

  return hotspotFiles.length > 0 ? saturated / hotspotFiles.length : 1.0;
}

